import { 菩薩坐身, 前臂 } from './pusa.js';
import { 側拳, 腕釧 } from '../bujian/index.js';
export const 金剛笑 = (bi) => 菩薩坐身(bi, {
    髮先: true,
    臂(bi, 筆) {
        const { M, C, Qk, S, 骨, 細, 陰, 陽 } = 筆;
        // 舉臂：肩峰而外上，肘揚於肩際（左陽右陰，杆自肩發而上翻）
        骨(() => {
            陽(() => {
                M(-13.4, 28.6);
                C(-15.4, 27.8, -16.6, 26.6, -17.1, 24.9);
                S();
                M(-10.9, 32.4);
                C(-12.7, 30.7, -13.9, 29.0, -14.4, 27.4);
                S();
            });
            陰(() => {
                M(13.4, 28.6);
                C(15.4, 27.8, 16.6, 26.6, 17.1, 24.9);
                S();
                M(10.9, 32.4);
                C(12.7, 30.7, 13.9, 29.0, 14.4, 27.4);
                S();
            });
        });
        // 前臂上舉至耳際
        骨(() => 陽(() => 前臂(bi, 筆, [-16.4, 25.3], [-11.4, 18.0], { 寬根: 2.4, 寬梢: 1.8, 弓: 0.35, 肘帽: true })));
        骨(() => 陰(() => 前臂(bi, 筆, [16.4, 25.3], [11.4, 18.0], { 寬根: 2.4, 寬梢: 1.8, 弓: -0.35, 肘帽: true })));
        // 二拳舉於耳側（拳背向耳；蔽法自斷髮縷）
        側拳(bi, -9.9, 15.9, 2.23, 1.12);
        側拳(bi, 9.9, 15.9, -2.23, 1.12, -1);
        // 嚴：舉臂之釧隨臂勢（上臂斜舉，環貫其軸）
        細(() => {
            for (const d of [-1, 1]) {
                M(d * 13.1, 26.4);
                Qk(d * 14.4, 27.3, d * 15.6, 26.5);
                S();
                M(d * 13.6, 25.5);
                Qk(d * 14.9, 26.4, d * 16.1, 25.6);
                S();
                bi.dot(d * 14.9, 26.35, 0.2);
            }
            腕釧(bi, [[-12.7, 18.5, -11.7, 19.2, -10.7, 19.4], [-12.3, 17.6, -11.3, 18.3, -10.3, 18.5]], [-11.5, 18.8]);
            腕釧(bi, [[12.7, 18.5, 11.7, 19.2, 10.7, 19.4], [12.3, 17.6, 11.3, 18.3, 10.3, 18.5]], [11.5, 18.8]);
        });
    },
});
